// TestRegression tests for the library scanner failures with updated Trivy components
func TestRegression(t *testing.T) {
	t.Run("AnalyzerGroupCreation", testAnalyzerGroupCreation)
	t.Run("PNPMLockfileEcosystemSupport", testPNPMLockfileSupport)
	t.Run("DotNetEcosystemSupport", testDotNetEcosystemSupport)
	t.Run("LibraryScannerDisabledAnalyzers", testLibraryScannerDisabledAnalyzers)
}

// testAnalyzerGroupCreation verifies that the analyzer group can be created
// with the correct disabled analyzers list
func testAnalyzerGroupCreation(t *testing.T) {
	disabledAnalyzers := []analyzer.Type{
		// OS analyzers should be disabled for library scanning
		analyzer.TypeOSRelease,
		analyzer.TypeAlpine,
		analyzer.TypeAmazon,
		analyzer.TypeDebian,
		analyzer.TypeUbuntu,
		// OS Package analyzers should be disabled
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		// Secrets analyzer should be disabled
		analyzer.TypeSecret,
		// License analyzer should be disabled
		analyzer.TypeLicenseFile,
	}

	// This should not panic or error
	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)
	if anal == nil {
		t.Fatal("Expected analyzer group to be created, got nil")
	}
}

// testPNPMLockfileSupport verifies that PNPM lockfiles (pnpm-lock.yaml) are recognized
// as a library ecosystem
func testPNPMLockfileSupport(t *testing.T) {
	// Test that pnpm-lock.yaml is analyzed correctly
	pnpmLockContent := `lockfileVersion: 5.4

specifiers:
  express: ^4.18.0
  react: ^18.0.0

packages:
  /express@4.18.0:
    engines:
      node: '>= 0.10.0'
    hasBin: true
    dev: false

dependencies:
  express: 4.18.0
  react: 18.0.0

devDependencies: {}
`

	ctx := context.Background()
	disabledAnalyzers := getStandardDisabledAnalyzers()
	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	result := new(analyzer.AnalysisResult)
	var wg sync.WaitGroup

	// Attempt to analyze a PNPM lockfile
	err := anal.AnalyzeFile(
		ctx,
		&wg,
		semaphore.NewWeighted(1),
		result,
		"",
		"pnpm-lock.yaml",
		&DummyFileInfo{size: int64(len(pnpmLockContent)), filemode: 0644},
		func() (dio.ReadSeekCloserAt, error) {
			return dio.NopCloser(bytes.NewReader([]byte(pnpmLockContent))), nil
		},
		nil,
		analyzer.AnalysisOptions{Offline: true},
	)

	if err != nil {
		t.Logf("Error analyzing pnpm-lock.yaml: %v", err)
		// Even if it errors, we're checking if the analyzer recognizes the file type
		// The issue is that PNPM files may not be properly recognized in the ecosystem detection
	}

	// Check if applications were detected (would be empty if pnpm ecosystem not supported)
	if result != nil && len(result.Applications) == 0 {
		t.Logf("WARNING: No applications detected for pnpm-lock.yaml - ecosystem may not be supported")
	}
}

// testDotNetEcosystemSupport verifies that .NET lockfiles are recognized
func testDotNetEcosystemSupport(t *testing.T) {
