	dotnetLockContent := `{
  "version": 1,
  "dependencies": {
    "System.Net.Http": {
      "version": "4.3.4"
    }
  }
}
`

	ctx := context.Background()
	disabledAnalyzers := getStandardDisabledAnalyzers()
	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	result := new(analyzer.AnalysisResult)
	var wg sync.WaitGroup

	err := anal.AnalyzeFile(
		ctx,
		&wg,
		semaphore.NewWeighted(1),
		result,
		"",
		"packages.lock.json",
		&DummyFileInfo{size: int64(len(dotnetLockContent)), filemode: 0644},
		func() (dio.ReadSeekCloserAt, error) {
			return dio.NopCloser(bytes.NewReader([]byte(dotnetLockContent))), nil
		},
		nil,
		analyzer.AnalysisOptions{Offline: true},
	)

	if err != nil {
		t.Logf("Error analyzing packages.lock.json: %v", err)
	}

	if result != nil && len(result.Applications) == 0 {
		t.Logf("WARNING: No applications detected for packages.lock.json - .NET ecosystem may not be supported")
	}
}

// testLibraryScannerDisabledAnalyzers verifies that non-library analyzers are properly disabled
// to prevent unnecessary execution during library scans
func testLibraryScannerDisabledAnalyzers(t *testing.T) {
	expectedDisabledTypes := map[analyzer.Type]bool{
		// OS analyzers should be disabled
		analyzer.TypeOSRelease:            true,
		analyzer.TypeAlpine:               true,
		analyzer.TypeDebian:               true,
		analyzer.TypeUbuntu:               true,
		// Secrets should be disabled
		analyzer.TypeSecret:               true,
		// Licenses should be disabled
		analyzer.TypeLicenseFile:          true,
		// Config file analyzers should be disabled
		analyzer.TypeYaml:                 true,
		analyzer.TypeJSON:                 true,
		analyzer.TypeDockerfile:           true,
	}

	disabledAnalyzers := getStandardDisabledAnalyzers()
	disabledSet := make(map[analyzer.Type]bool)
	for _, at := range disabledAnalyzers {
		disabledSet[at] = true
	}

	for expectedType, shouldBeDisabled := range expectedDisabledTypes {
		isDisabled := disabledSet[expectedType]
		if shouldBeDisabled && !isDisabled {
			t.Errorf("Expected analyzer %v to be disabled for library scans, but it's not", expectedType)
		}
	}

	t.Logf("Verified %d analyzer types are properly disabled", len(disabledAnalyzers))
}

